sys_script.script:
(function executeRule(current, previous) {

    try {

        var description = current.emotional_description + '';

        var rm = new sn_ws.RESTMessageV2('Groq AI', 'Analyze');

        var requestBody = {
            model: "llama-3.1-8b-instant",
            messages: [
                {
                    role: "system",
                    content: "You are a mental health triage assistant. Return ONLY JSON in this format: {\"risk\":\"Low|Medium|High|Critical\",\"summary\":\"...\",\"recommendation\":\"...\"}"
                },
                {
                    role: "user",
                    content: description
                }
            ]
        };

        rm.setRequestBody(JSON.stringify(requestBody));

        var response = rm.execute();

        var responseBody = response.getBody();
		gs.info("Groq Response = " + responseBody);

        gs.info("Groq Response: " + responseBody);

        var result = JSON.parse(responseBody);

        var aiText = result.choices[0].message.content;
		gs.info("AI Content = " + aiText);

        var aiJson = JSON.parse(aiText);

        current.ai_risk_level = aiJson.risk;
        current.ai_summary = aiJson.summary;
        current.ai_recommendation = aiJson.recommendation;
        current.ai_analyzed = true;
		current.update();

    } catch (e) {

        gs.error("MindBridge AI Error: " + e);

        current.ai_risk_level = "Medium";
        current.ai_summary = "AI analysis failed.";
        current.ai_recommendation = "Manual counselor review required.";
		current.update();
    }

})(current, previous);
